#!/usr/bin/env python3
import subprocess
import sys
import os
import hashlib
import json
from pathlib import Path

def verify_requirements_integrity():
    """Verify requirements.txt hasn't been tampered with using hash verification"""
    requirements_file = Path('requirements.txt')
    hash_file = Path('requirements.txt.sha256')
    
    if not requirements_file.exists():
        print("Error: requirements.txt not found")
        sys.exit(1)
    
    if hash_file.exists():
        with open(requirements_file, 'rb') as f:
            current_hash = hashlib.sha256(f.read()).hexdigest()
        with open(hash_file, 'r') as f:
            expected_hash = f.read().strip()
        if current_hash != expected_hash:
            print("Warning: requirements.txt hash mismatch")

def install_dependencies():
    """Install dependencies with security constraints"""
    print("Installing dependencies...")
    
    # Use pip with security flags
    cmd = [
        sys.executable, '-m', 'pip', 'install',
        '--require-hashes',  # Require hash verification
        '--no-deps',  # Install only what's listed
        '-r', 'requirements.txt',
        '--only-binary', ':all:',  # Only use wheels, no source builds
        '--no-cache-dir',  # Don't use cache to ensure fresh install
        '--disable-pip-version-check'
    ]
    
    # If --require-hashes is too strict for your workflow, use these alternatives:
    alternative_cmd = [
        sys.executable, '-m', 'pip', 'install',
        '-r', 'requirements.txt',
        '--no-cache-dir',
        '--disable-pip-version-check',
        '--upgrade',
        '--force-reinstall'
    ]
    
    try:
        result = subprocess.run(cmd, check=True, capture_output=True, text=True)
        print(result.stdout)
    except subprocess.CalledProcessError:
        print("Hash verification failed, trying alternative installation...")
        result = subprocess.run(alternative_cmd, check=True, capture_output=True, text=True)
        print(result.stdout)

def check_vulnerable_packages():
    """Check for known vulnerabilities in installed packages"""
    print("Checking for vulnerable packages...")
    
    try:
        # Use pip-audit or safety for vulnerability scanning
        result = subprocess.run(
            [sys.executable, '-m', 'pip', 'list', '--format=json'],
            check=True,
            capture_output=True,
            text=True
        )
        
        packages = json.loads(result.stdout)
        
        # Known vulnerable packages to check (example list - update regularly)
        vulnerable_patterns = {
            'urllib3': '1.26.5',  # Example: versions below 1.26.5 have vulnerabilities
            'requests': '2.25.0',
            'cryptography': '3.3.2',
            'pyyaml': '5.4',
            'pillow': '8.3.2',
            'django': '3.2.0',
            'flask': '2.0.0'
        }
        
        for pkg in packages:
            name = pkg['name'].lower()
            version = pkg['version']
            if name in vulnerable_patterns:
                print(f"Warning: {name} version {version} may be outdated")
        
    except subprocess.CalledProcessError as e:
        print(f"Warning: Could not check package versions: {e}")

def run_tests():
    """Run application tests"""
    print("Running tests...")
    
    test_commands = [
        [sys.executable, '-m', 'pytest', '--tb=short', '--strict-markers'],
        [sys.executable, '-m', 'unittest', 'discover', '-s', 'tests'],
        [sys.executable, 'manage.py', 'test']
    ]
    
    for cmd in test_commands:
        if Path(cmd[-1] if len(cmd) > 2 else 'tests').exists() or 'pytest' in cmd[2]:
            try:
                result = subprocess.run(cmd, check=True, capture_output=True, text=True, timeout=300)
                print(result.stdout)
                return True
            except (subprocess.CalledProcessError, FileNotFoundError, subprocess.TimeoutExpired):
                continue
    
    print("No tests found or all test runners failed")
    return False

def package_deployment():
    """Package application for deployment"""
    print("Packaging for deployment...")
    
    # Create deployment directory
    deploy_dir = Path('deploy')
    deploy_dir.mkdir(exist_ok=True)
    
    # Copy necessary files
    files_to_package = [
        'requirements.txt',
        'app.py',
        'main.py',
        'wsgi.py',
        'manage.py'
    ]
    
    import shutil
    
    for file in files_to_package:
        if Path(file).exists():
            shutil.copy2(file, deploy_dir / file)
    
    # Copy directories
    dirs_to_package = ['app', 'src', 'static', 'templates', 'config']
    
    for dir_name in dirs_to_package:
        src_dir = Path(dir_name)
        if src_dir.exists() and src_dir.is_dir():
            dst_dir = deploy_dir / dir_name
            if dst_dir.exists():
                shutil.rmtree(dst_dir)
            shutil.copytree(src_dir, dst_dir)
    
    # Create deployment archive
    archive_name = 'deployment'
    shutil.make_archive(archive_name, 'zip', deploy_dir)
    
    print(f"Deployment package created: {archive_name}.zip")

def main():
    """Main deployment workflow"""
    print("Starting deployment automation...")
    
    try:
        # Verify integrity
        verify_requirements_integrity()
        
        # Install dependencies
        install_dependencies()
        
        # Check for vulnerabilities
        check_vulnerable_packages()
        
        # Run tests
        if not run_tests():
            print("Warning: Tests did not run successfully")
        
        # Package for deployment
        package_deployment()
        
        print("Deployment automation completed successfully!")
        
    except subprocess.CalledProcessError as e:
        print(f"Error during deployment: {e}")
        if e.stderr:
            print(e.stderr)
        sys.exit(1)
    except Exception as e:
        print(f"Unexpected error: {e}")
        sys.exit(1)

if __name__ == '__main__':
    main()